module up_counter (
    input rst_clk,
    input reset,
    input en,
    input preset,
    input [13:0] preset_val,
    output reg [13:0] q);

always @(posedge rst_clk or posedge reset) begin
    if (reset)
        q <= 14'b00000000000000;
    else if (preset)
        q <= preset_val;
    else if (en)
        q <= q + 1;
end

endmodule
